    }

    // Precompute left array where left[i] is the start of the increasing sequence ending at i
    int[] left = new int[n];
    left[0] = 0;
    for (int i = 1; i < n; i++) {
        if (nums[i] > nums[i - 1]) {
            left[i] = left[i - 1];
        } else {
            left[i] = i;
        }
    }

    // Precompute right array where right[i] is the end of the increasing sequence starting at i
    int[] right = new int[n];
    right[n - 1] = n - 1;
    for (int i = n - 2; i >= 0; i--) {
        if (nums[i] < nums[i + 1]) {
            right[i] = right[i + 1];
        } else {
            right[i] = i;
        }
    }

    // Iterate all possible p and q positions
    for (int p = 1; p < n - 2; p++) {
        for (int q = p + 1; q < n - 1; q++) {
            // Check if nums[left[p]..p] is strictly increasing
