                continue;
            }
            // Check if nums[p..q] is strictly decreasing
            if (nums[p] <= nums[q] || (q > p + 1 && nums[q - 1] <= nums[q])) {
                continue;
            }
            // Check if nums[q..right[q]] is strictly increasing
            if (right[q] == q || nums[q] >= nums[q + 1]) {
                continue;
            }

