public static long solve(long[] nums) {
    int n = nums.length;
    long[] prefixSum = new long[n + 1];
    for (int i = 0; i < n; i++) {
        prefixSum[i + 1] = prefixSum[i] + nums[i];
    }

    long[] leftMax = new long[n];
    long[] rightMax = new long[n];

    // Compute leftMax: maximum prefixSum[p+1] where nums[l..p] is strictly increasing
    leftMax[0] = prefixSum[1];
    for (int i = 1; i < n; i++) {
        if (nums[i] > nums[i - 1]) {
            leftMax[i] = Math.max(leftMax[i - 1], prefixSum[i + 1]);
        } else {
            leftMax[i] = Long.MIN_VALUE;
        }
    }

    // Compute rightMax: maximum (prefixSum[r+1] - prefixSum[q]) where nums[q..r] is strictly increasing
    rightMax[n - 1] = nums[n - 1];
    for (int i = n - 2; i >= 0; i--) {
        if (nums[i] < nums[i + 1]) {
            rightMax[i] = Math.max(rightMax[i + 1] + nums[i], nums[i]);
        } else {
            rightMax[i] = nums[i];
        }
    }

    long maxSum = Long.MIN_VALUE;
    // Iterate for possible p and q where nums[p..q] is strictly decreasing
    for (int p = 1; p < n - 2; p++) {
        if (nums[p] > nums[p + 1]) {
            int q = p + 1;
            while (q + 1 < n && nums[q] > nums[q + 1]) {
                q++;
            }
            // Now nums[p..q] is strictly decreasing
            if (leftMax[p] != Long.MIN_VALUE && q < n - 1) {
                long currentSum = leftMax[p] + (prefixSum[q + 1] - prefixSum[p + 1]) + rightMax[q + 1];
                if (currentSum > maxSum) {
                    maxSum = currentSum;
                }
            }
            p = q - 1; // Skip ahead
        }
    }
    return maxSum;
}
