public static long solve(long[] nums) {
    int n = nums.length;
    long maxSum = Long.MIN_VALUE;

    // Precompute prefix sums for quick range sum calculation
    long[] prefix = new long[n + 1];
    for (int i = 0; i < n; i++) {
        prefix[i + 1] = prefix[i] + nums[i];
    }

    // Precompute left increasing and right increasing segments
    int[] leftInc = new int[n];
    int[] rightInc = new int[n];

    // Fill leftInc: leftInc[i] is the length of the longest increasing segment ending at i
    leftInc[0] = 1;
    for (int i = 1; i < n; i++) {
        if (nums[i] > nums[i - 1]) {
            leftInc[i] = leftInc[i - 1] + 1;
        } else {
            leftInc[i] = 1;
        }
    }

    // Fill rightInc: rightInc[i] is the length of the longest increasing segment starting at i
    rightInc[n - 1] = 1;
    for (int i = n - 2; i >= 0; i--) {
        if (nums[i] < nums[i + 1]) {
            rightInc[i] = rightInc[i + 1] + 1;
        } else {
            rightInc[i] = 1;
        }
    }

    // Iterate through all possible p and q
    for (int p = 1; p < n - 2; p++) {
        for (int q = p + 1; q < n - 1; q++) {
            // Check if nums[p] > nums[q] (decreasing segment between p and q)
            if (nums[p] > nums[q]) {
                // Check left increasing segment ending at p
                int l = p - leftInc[p] + 1;
                // Check right increasing segment starting at q
                int r = q + rightInc[q] - 1;
                // Ensure l < p < q < r
                if (l < p && p < q && q < r) {
                    long sum = prefix[r + 1] - prefix[l];
                    if (sum > maxSum) {
                        maxSum = sum;
                    }
                }
            }
        }
    }

    return maxSum;
}
