    long maxSum = Long.MIN_VALUE;

    // Precompute prefix sums for quick range sum calculation
    long[] prefix = new long[n + 1];
    for (int i = 0; i < n; i++) {
        prefix[i + 1] = prefix[i] + nums[i];
    }

    // Precompute left increasing and right increasing arrays
    int[] leftInc = new int[n]; // leftInc[i] is the length of the longest increasing sequence ending at i
    for (int i = 1; i < n; i++) {
        if (nums[i] > nums[i - 1]) {
            leftInc[i] = leftInc[i - 1] + 1;
        } else {
            leftInc[i] = 0;
        }
    }

    int[] rightInc = new int[n]; // rightInc[i] is the length of the longest increasing sequence starting at i
    for (int i = n - 2; i >= 0; i--) {
        if (nums[i] < nums[i + 1]) {
            rightInc[i] = rightInc[i + 1] + 1;
        } else {
            rightInc[i] = 0;
        }
    }

    // Iterate all possible p and q positions
    for (int p = 1; p < n - 2; p++) {
        for (int q = p + 1; q < n - 1; q++) {
            // Check if nums[p] > nums[q] (decreasing)
            if (nums[p] <= nums[q]) {
                continue;
            }

            // Check left increasing part: l can be from p - leftInc[p] to p-1
            int lStart = p - leftInc[p];
            if (lStart < 0) {
                continue;
            }

            // Check right increasing part: r can be from q + 1 to q + rightInc[q]
            int rEnd = q + rightInc[q];
            if (rEnd >= n) {
                continue;
            }

            // Calculate the sum from lStart to rEnd
            long currentSum = prefix[rEnd + 1] - prefix[lStart];
            if (currentSum > maxSum) {
                maxSum = currentSum;
            }
        }
    }

    return maxSum;
}
