    long[] prefix = new long[n + 1];
    for (int i = 0; i < n; i++) {
        prefix[i + 1] = prefix[i] + nums[i];
    }

    // Precompute left increasing segments
    int[] leftInc = new int[n];
    for (int i = 1; i < n; i++) {
        if (nums[i] > nums[i - 1]) {
            leftInc[i] = leftInc[i - 1] + 1;
        } else {
            leftInc[i] = 0;
        }
    }

    // Precompute right increasing segments
    int[] rightInc = new int[n];
    for (int i = n - 2; i >= 0; i--) {
        if (nums[i] < nums[i + 1]) {
            rightInc[i] = rightInc[i + 1] + 1;
        } else {
            rightInc[i] = 0;
        }
    }

    // Precompute left peaks (p) where nums[p] is a peak in the left increasing segment
    for (int p = 1; p < n - 2; p++) {
        if (leftInc[p] > 0 && (p == n - 1 || nums[p] > nums[p + 1])) {
            // Now find q where nums[p..q] is strictly decreasing and nums[q..r] is strictly increasing
            for (int q = p + 1; q < n - 1; q++) {
                if (nums[q] < nums[q - 1] && rightInc[q] > 0) {
                    // Valid q found, now find r
                    int r = q + rightInc[q];
                    if (r < n) {
                        long sum = prefix[r + 1] - prefix[p - leftInc[p]];
                        if (sum > maxSum) {
                            maxSum = sum;
                        }
                    }
                } else if (nums[q] >= nums[q - 1]) {
                    break; // Not strictly decreasing anymore
