public static long solve(long[] nums) {
    int n = nums.length;
    long maxSum = Long.MIN_VALUE;

    // Precompute prefix sums for quick range sum calculation
    long[] prefixSum = new long[n + 1];
    for (int i = 0; i < n; i++) {
        prefixSum[i + 1] = prefixSum[i] + nums[i];
    }

    // Precompute left increasing and right increasing arrays
    int[] leftInc = new int[n];
    int[] rightInc = new int[n];

    // leftInc[i] is the length of the longest increasing sequence ending at i
    leftInc[0] = 1;
    for (int i = 1; i < n; i++) {
        if (nums[i] > nums[i - 1]) {
            leftInc[i] = leftInc[i - 1] + 1;
        } else {
            leftInc[i] = 1;
        }
    }

    // rightInc[i] is the length of the longest increasing sequence starting at i
    rightInc[n - 1] = 1;
    for (int i = n - 2; i >= 0; i--) {
        if (nums[i] < nums[i + 1]) {
            rightInc[i] = rightInc[i + 1] + 1;
        } else {
            rightInc[i] = 1;
        }
    }

    // Iterate through all possible p and q
    for (int p = 1; p < n - 2; p++) {
        for (int q = p + 1; q < n - 1; q++) {
            // Check if nums[p] is a peak (leftInc[p] >= 2 and nums[p] > nums[p+1])
            if (leftInc[p] >= 2 && nums[p] > nums[p + 1]) {
                // Check if nums[q] is a trough (nums[q-1] > nums[q] and rightInc[q] >= 2)
                if (nums[q - 1] > nums[q] && rightInc[q] >= 2) {
                    // Calculate l and r
                    int l = p - leftInc[p] + 1;
                    int r = q + rightInc[q] - 1;
                    // Calculate the sum from l to r
                    long currentSum = prefixSum[r + 1] - prefixSum[l];
                    if (currentSum > maxSum) {
                        maxSum = currentSum;
                    }
                }
            }
        }
    }

    return maxSum;
}
