    int n = nums.length;
    long maxSum = Long.MIN_VALUE;

    // Precompute prefix sums for quick range sum calculation
    long[] prefixSum = new long[n + 1];
    for (int i = 0; i < n; i++) {
        prefixSum[i + 1] = prefixSum[i] + nums[i];
    }

    // Precompute left increasing and right increasing segments
    int[] leftInc = new int[n]; // leftInc[i] is the length of increasing segment ending at i
    int[] rightInc = new int[n]; // rightInc[i] is the length of increasing segment starting at i

    leftInc[0] = 1;
    for (int i = 1; i < n; i++) {
        if (nums[i] > nums[i - 1]) {
            leftInc[i] = leftInc[i - 1] + 1;
        } else {
            leftInc[i] = 1;
        }
    }

    rightInc[n - 1] = 1;
    for (int i = n - 2; i >= 0; i--) {
        if (nums[i] < nums[i + 1]) {
            rightInc[i] = rightInc[i + 1] + 1;
        } else {
            rightInc[i] = 1;
        }
    }

    // Iterate all possible p and q positions
    for (int p = 1; p < n - 2; p++) {
        for (int q = p + 1; q < n - 1; q++) {
            // Check if nums[p] > nums[q] (decreasing)
            if (nums[p] <= nums[q]) {
                continue;
            }
            // Check left increasing segment (l must be <= p - leftInc[p] + 1)
            int lStart = p - leftInc[p] + 1;
            if (lStart < 0 || leftInc[p] < 2) {
                continue;
            }
            // Check right increasing segment (r must be >= q + rightInc[q] - 1)
            int rEnd = q + rightInc[q] - 1;
            if (rEnd >= n || rightInc[q] < 2) {
                continue;
            }
            // Calculate the sum from lStart to rEnd
            long currentSum = prefixSum[rEnd + 1] - prefixSum[lStart];
            if (currentSum > maxSum) {
                maxSum = currentSum;
            }
        }
    }

    return maxSum;
}
