    long[] prefix = new long[n + 1];
    for (int i = 0; i < n; i++) {
        prefix[i + 1] = prefix[i] + nums[i];
    }

    // Precompute left increasing segments
    int[] leftInc = new int[n];
    for (int i = 1; i < n; i++) {
        if (nums[i] > nums[i - 1]) {
            leftInc[i] = leftInc[i - 1] + 1;
        } else {
            leftInc[i] = 0;
        }
    }

    // Precompute right increasing segments
    int[] rightInc = new int[n];
    for (int i = n - 2; i >= 0; i--) {
        if (nums[i] < nums[i + 1]) {
            rightInc[i] = rightInc[i + 1] + 1;
        } else {
            rightInc[i] = 0;
        }
    }

    // Precompute left decreasing segments (actually right to left increasing)
    int[] leftDec = new int[n];
    for (int i = n - 2; i >= 0; i--) {
        if (nums[i] > nums[i + 1]) {
            leftDec[i] = leftDec[i + 1] + 1;
        } else {
            leftDec[i] = 0;
        }
    }

    // Iterate all possible p and q positions
    for (int p = 1; p < n - 2; p++) {
        for (int q = p + 1; q < n - 1; q++) {
            // Check if nums[l..p] is strictly increasing
            if (leftInc[p] >= 1) {
                int l = p - leftInc[p];
                // Check if nums[p..q] is strictly decreasing
                if (leftDec[p] >= q - p) {
                    // Check if nums[q..r] is strictly increasing
                    if (rightInc[q] >= 1) {
                        int r = q + rightInc[q];
                        long sum = prefix[r + 1] - prefix[l];
                        if (sum > maxSum) {
