public static long solve(long[] nums) {
    int n = nums.length;
    long maxSum = Long.MIN_VALUE;

    // Precompute prefix sums for quick range sum calculation
    long[] prefix = new long[n + 1];
    for (int i = 0; i < n; i++) {
        prefix[i + 1] = prefix[i] + nums[i];
    }

    // Precompute left increasing segments
    int[] leftInc = new int[n];
    leftInc[0] = 0;
    for (int i = 1; i < n; i++) {
        if (nums[i] > nums[i - 1]) {
            leftInc[i] = leftInc[i - 1];
        } else {
            leftInc[i] = i;
        }
    }

    // Precompute right increasing segments
    int[] rightInc = new int[n];
    rightInc[n - 1] = n - 1;
    for (int i = n - 2; i >= 0; i--) {
        if (nums[i] < nums[i + 1]) {
            rightInc[i] = rightInc[i + 1];
        } else {
            rightInc[i] = i;
        }
    }

    // Precompute left decreasing segments (from p to q)
    int[] leftDec = new int[n];
    leftDec[0] = 0;
    for (int i = 1; i < n; i++) {
        if (nums[i] < nums[i - 1]) {
            leftDec[i] = leftDec[i - 1];
        } else {
            leftDec[i] = i;
        }
    }

    // Iterate all possible p and q positions
    for (int p = 1; p < n - 2; p++) {
        for (int q = p + 1; q < n - 1; q++) {
            // Check if nums[l..p] is strictly increasing
            int l = leftInc[p];
            if (l == p) continue; // needs at least 2 elements

            // Check if nums[p..q] is strictly decreasing
            if (leftDec[q] > p) continue;

            // Check if nums[q..r] is strictly increasing
            int r = rightInc[q];
            if (r == q) continue; // needs at least 2 elements

            // Calculate the sum from l to r
            long sum = prefix[r + 1] - prefix[l];
            if (sum > maxSum) {
                maxSum = sum;
            }
        }
    }

    return maxSum;
}
