public static long solve(long[] nums) {
    int n = nums.length;
    long maxSum = Long.MIN_VALUE;

    // Precompute prefix sums for quick range sum calculation
    long[] prefixSum = new long[n + 1];
    for (int i = 0; i < n; i++) {
        prefixSum[i + 1] = prefixSum[i] + nums[i];
    }

    // Precompute left increasing segments
    int[] leftInc = new int[n];
    leftInc[0] = 0;
    for (int i = 1; i < n; i++) {
        if (nums[i] > nums[i - 1]) {
            leftInc[i] = leftInc[i - 1];
        } else {
            leftInc[i] = i;
        }
    }

    // Precompute right increasing segments
    int[] rightInc = new int[n];
    rightInc[n - 1] = n - 1;
    for (int i = n - 2; i >= 0; i--) {
        if (nums[i] < nums[i + 1]) {
            rightInc[i] = rightInc[i + 1];
        } else {
            rightInc[i] = i;
        }
    }

    // Iterate through all possible p and q
    for (int p = 1; p < n - 2; p++) {
        for (int q = p + 1; q < n - 1; q++) {
            // Check if nums[p] > nums[q] (decreasing segment)
            if (nums[p] <= nums[q]) {
                continue;
            }

            // Find l: leftInc[p] is the start of the increasing segment ending at p
            int l = leftInc[p];
            if (l >= p) {
                continue; // no increasing segment to the left of p
            }

            // Find r: rightInc[q] is the end of the increasing segment starting at q
            int r = rightInc[q];
            if (r <= q) {
                continue; // no increasing segment to the right of q
            }

            // Calculate the sum from l to r
            long currentSum = prefixSum[r + 1] - prefixSum[l];
            if (currentSum > maxSum) {
                maxSum = currentSum;
            }
        }
    }

    return maxSum;
}
