public static long solve(long[] nums) {
    int n = nums.length;
    long[] prefixSum = new long[n + 1];
    for (int i = 0; i < n; i++) {
        prefixSum[i + 1] = prefixSum[i] + nums[i];
    }

    // left[i] is the first index <=i where nums starts increasing up to i
    int[] left = new int[n];
    left[0] = 0;
    for (int i = 1; i < n; i++) {
        if (nums[i] > nums[i - 1]) {
            left[i] = left[i - 1];
        } else {
            left[i] = i;
        }
    }

    // right[i] is the first index >=i where nums starts increasing from i
    int[] right = new int[n];
    right[n - 1] = n - 1;
    for (int i = n - 2; i >= 0; i--) {
        if (nums[i] < nums[i + 1]) {
            right[i] = right[i + 1];
        } else {
            right[i] = i;
        }
    }

    long maxSum = Long.MIN_VALUE;
    for (int p = 1; p < n - 2; p++) {
        for (int q = p + 1; q < n - 1; q++) {
            if (nums[p] > nums[q]) {
                int l = left[p];
                int r = right[q];
                if (l < p && q < r) {
                    long sum = prefixSum[r + 1] - prefixSum[l];
                    if (sum > maxSum) {
                        maxSum = sum;
                    }
                }
            }
        }
    }
    return maxSum;
}
