public static long solve(long[] nums) {
    int n = nums.length;
    long maxSum = Long.MIN_VALUE;

    // Precompute prefix sums for quick range sum calculation
    long[] prefix = new long[n + 1];
    for (int i = 0; i < n; i++) {
        prefix[i + 1] = prefix[i] + nums[i];
    }

    // Precompute left increasing and right increasing segments
    int[] leftInc = new int[n]; // leftInc[i] is the length of the longest increasing segment ending at i
    for (int i = 1; i < n; i++) {
        if (nums[i] > nums[i - 1]) {
            leftInc[i] = leftInc[i - 1] + 1;
        } else {
            leftInc[i] = 0;
        }
    }

    int[] rightInc = new int[n]; // rightInc[i] is the length of the longest increasing segment starting at i
    for (int i = n - 2; i >= 0; i--) {
        if (nums[i] < nums[i + 1]) {
            rightInc[i] = rightInc[i + 1] + 1;
        } else {
            rightInc[i] = 0;
        }
    }

    // Iterate all possible p and q positions
    for (int p = 1; p < n - 2; p++) {
        for (int q = p + 1; q < n - 1; q++) {
            // Check if nums[l..p] is strictly increasing (l is p - leftInc[p])
            int l = p - leftInc[p];
            if (l < 0 || leftInc[p] < 1) continue;

            // Check if nums[q..r] is strictly increasing (r is q + rightInc[q])
            int r = q + rightInc[q];
            if (r >= n || rightInc[q] < 1) continue;

            // Check if nums[p..q] is strictly decreasing
            boolean valid = true;
            for (int i = p; i < q; i++) {
                if (nums[i] <= nums[i + 1]) {
                    valid = false;
                    break;
                }
            }
            if (!valid) continue;

            // Calculate the sum from l to r
            long currentSum = prefix[r + 1] - prefix[l];
            if (currentSum > maxSum) {
                maxSum = currentSum;
            }
        }
    }

    return maxSum;
}
